const body = $input.item.json.body || $input.item.json;
if (!body || typeof body !== 'object') {
  throw new Error('Empty or invalid audit payload');
}
const audit = body.audit || body;
if (typeof audit.score !== 'number') {
  throw new Error('audit.score is missing or not a number');
}
if (!Array.isArray(audit.findings)) {
  throw new Error('audit.findings must be an array');
}
return [{ json: {
  audit,
  receivedAt: new Date().toISOString(),
  source: body.source || 'apex',
  requestId: $execution.id
} }];

const audit = $json.audit;
const sev = (f) => f.severity || f.priority || '?';
const findings = (audit.findings || []).map((f, i) => {
  const head = `### Finding ${i+1} [${sev(f)}] ${f.title || '(sans titre)'}`;
  const lines = [head];
  if (f.location || f.file) lines.push('- Localisation : `' + (f.location || f.file) + '`');
  if (f.description) lines.push('- Description : ' + f.description);
  if (f.cwe) lines.push('- CWE : ' + f.cwe);
  if (f.cvss) lines.push('- CVSS : ' + f.cvss);
  return lines.join('
');
}).join('

');
const ctx = audit.context && typeof audit.context === 'object'
  ? Object.entries(audit.context).map(([k,v]) => `- **${k}** : ${v}`).join('
')
  : (audit.context || '_(non fourni)_');
const userPrompt = `# Audit Apex à traiter

Score global : ${audit.score}/100
Verdict : ${audit.verdict || '(non fourni)'}
Date audit : ${audit.date || audit.timestamp || '(non datée)'}

## Findings

${findings || '_(aucun finding fourni)_'}

## Contexte projet

${ctx}

---

Génère le plan d'implémentation maintenant.`;
return [{ json: { ...$json, userPrompt } }];

