const r = $json;
const content = Array.isArray(r.content) ? r.content : [];
const plan = content.map(b => b.text || '').join('\n').trim();
const usage = r.usage || {};
const tokensIn = usage.input_tokens || 0;
const tokensOut = usage.output_tokens || 0;
const prev = $('Format Audit Payload').first().json;
return [{ json: {
  audit_payload: prev.audit,
  plan_response: plan,
  tokens_input: tokensIn,
  tokens_output: tokensOut,
  status: plan ? 'ok' : 'empty',
  request_id: prev.requestId,
  received_at: prev.receivedAt,
  model: r.model || 'unknown'
} }];
